import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { useAuth0 } from '@auth0/auth0-react';
import api from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const { isAuthenticated, isLoading, user: auth0User, getAccessTokenSilently, loginWithRedirect, logout } = useAuth0();
  const [currentUser, setCurrentUser] = useState(null);
  const [userLoading, setUserLoading] = useState(true);

  /** After Auth0 login, sync the user into our DB and attach the JWT to axios. */
  const syncUser = useCallback(async () => {
    if (!isAuthenticated) { setUserLoading(false); return; }
    try {
      const token = await getAccessTokenSilently();
      api.defaults.headers.common['Authorization'] = `Bearer ${token}`;

      const { data } = await api.post('/auth/sync');
      setCurrentUser(data.data.user);
    } catch (err) {
      console.error('User sync failed:', err);
    } finally {
      setUserLoading(false);
    }
  }, [isAuthenticated, getAccessTokenSilently]);

  useEffect(() => {
    if (!isLoading) syncUser();
  }, [isLoading, syncUser]);

  /** Refresh the token and update axios header. */
  const refreshToken = useCallback(async () => {
    const token = await getAccessTokenSilently({ ignoreCache: true });
    api.defaults.headers.common['Authorization'] = `Bearer ${token}`;
  }, [getAccessTokenSilently]);

  const handleLogout = () => {
    setCurrentUser(null);
    delete api.defaults.headers.common['Authorization'];
    logout({ logoutParams: { returnTo: window.location.origin } });
  };

  const isAdmin   = currentUser?.role === 'admin';
  const isManager = currentUser?.role === 'manager';
  const isAdminOrManager = isAdmin || isManager;

  return (
    <AuthContext.Provider value={{
      isAuthenticated,
      loading: isLoading || userLoading,
      currentUser,
      setCurrentUser,
      auth0User,
      isAdmin,
      isManager,
      isAdminOrManager,
      login: loginWithRedirect,
      logout: handleLogout,
      refreshToken,
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
};

export default AuthContext;
